{
  "name": "Shorts AI Storyboarder",
  "description": "Generate consistent 9:16 YouTube Shorts visuals from a script, character reference, and style video."
}

export interface Scene {
  id: string;
  scriptSegment: string;
  visualPrompt: string;
  imageUrl?: string;
  status: 'pending' | 'generating' | 'completed' | 'error';
}

export interface VideoStyleAnalysis {
  styleDescription: string;
  mood: string;
}

export enum AppStep {
  SETUP = 'SETUP',
  STORYBOARD = 'STORYBOARD',
}

export interface GenerationConfig {
  characterImage: string | null; // Base64
  referenceVideo: File | null;
  script: string;
  styleContext: string;
}

export const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      // Remove data URL prefix (e.g., "data:image/jpeg;base64,")
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = (error) => reject(error);
  });
};

export const cleanBase64 = (dataUrl: string): string => {
  if (dataUrl.includes(',')) {
    return dataUrl.split(',')[1];
  }
  return dataUrl;
};

import { GoogleGenAI, Type } from "@google/genai";
import { Scene } from "../types";
import { fileToBase64 } from "./utils";

// Initialize Gemini Client
// We use a getter to ensure we pick up the key if it changes (e.g. via selection)
const getAiClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

export const checkApiKey = async (): Promise<boolean> => {
  if (window.aistudio && window.aistudio.hasSelectedApiKey) {
     return await window.aistudio.hasSelectedApiKey();
  }
  return true; // Fallback if not in the specific environment
};

export const requestApiKey = async () => {
  if (window.aistudio && window.aistudio.openSelectKey) {
    await window.aistudio.openSelectKey();
  }
};

/**
 * Analyzes a reference video to extract style and mood.
 */
export const analyzeVideoStyle = async (videoFile: File): Promise<string> => {
  const ai = getAiClient();
  const base64Video = await fileToBase64(videoFile);

  // We use the flash preview model for multimodal analysis
  const modelId = "gemini-3-flash-preview"; 

  const prompt = `
    Analyze this video clip. describe the visual style, color palette, lighting, 
    and overall "vibe" (e.g., cyberpunk, fast-paced, minimalist, cinematic). 
    Keep it concise (under 50 words). This description will be used to generate similar images.
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: videoFile.type,
              data: base64Video,
            },
          },
          { text: prompt },
        ],
      },
    });
    return response.text || "Cinematic, high quality, trending on social media";
  } catch (error) {
    console.error("Video analysis failed", error);
    return "Cinematic, high quality";
  }
};

/**
 * Breaks down a script into scenes using JSON schema.
 */
export const generateScenesFromScript = async (script: string, styleContext: string): Promise<Scene[]> => {
  const ai = getAiClient();
  const modelId = "gemini-3-flash-preview";

  const prompt = `
    You are a professional storyboard artist for YouTube Shorts.
    Break down the following script into visual scenes. 
    Each scene should be 3-5 seconds long.

    The visual style should be: ${styleContext}.

    Return a list of scenes. For each scene provide:
    1. The segment of the script being spoken.
    2. A detailed visual prompt to generate an image for this scene. 
       The visual prompt MUST include the style description.
       If the script mentions a character, refer to them as "the main character".
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: [
        { text: prompt },
        { text: `SCRIPT:\n${script}` }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              scriptSegment: { type: Type.STRING },
              visualPrompt: { type: Type.STRING, description: "Detailed image generation prompt" },
            },
            required: ["scriptSegment", "visualPrompt"],
          },
        },
      },
    });

    if (response.text) {
      const rawScenes = JSON.parse(response.text);
      return rawScenes.map((s: any, index: number) => ({
        id: `scene-${index}-${Date.now()}`,
        scriptSegment: s.scriptSegment,
        visualPrompt: s.visualPrompt,
        status: 'pending'
      }));
    }
    return [];
  } catch (error) {
    console.error("Scene generation failed", error);
    throw error;
  }
};

/**
 * Generates an image for a specific scene using the character reference.
 */
export const generateSceneImage = async (
  scene: Scene, 
  characterImageBase64: string | null
): Promise<string> => {
  const ai = getAiClient();
  // Using Pro Image model for highest quality and 9:16 support with image input
  const modelId = "gemini-3-pro-image-preview"; 

  const parts: any[] = [];

  // If we have a character reference, include it first
  if (characterImageBase64) {
    parts.push({
      inlineData: {
        mimeType: "image/png", // Assuming generic image/png for simplicity, works for most
        data: characterImageBase64,
      },
    });

    // When providing an image, the model treats the text as an edit/generation instruction based on that image.
    // We emphasize keeping the character consistent.
    parts.push({
      text: `Generate a new scene based on this character. 
      Keep the character's facial features and clothing consistent if visible.
      Scene description: ${scene.visualPrompt}.
      Ensure the aspect ratio fits a 9:16 frame naturally.`
    });
  } else {
    parts.push({ text: scene.visualPrompt });
  }

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: { parts },
      config: {
        imageConfig: {
          aspectRatio: "9:16",
          imageSize: "2K" // High quality for Shorts
        }
      }
    });

    // Extract image
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    throw new Error("No image data found in response");
  } catch (error) {
    console.error("Image generation failed", error);
    throw error;
  }
};

import React, { useEffect, useState } from 'react';
import { checkApiKey, requestApiKey } from '../services/geminiService';

export const ApiKeyModal: React.FC<{ onReady: () => void }> = ({ onReady }) => {
  const [hasKey, setHasKey] = useState(false);

  const verifyKey = async () => {
    try {
      const valid = await checkApiKey();
      setHasKey(valid);
      if (valid) onReady();
    } catch (e) {
      console.error(e);
    }
  };

  useEffect(() => {
    verifyKey();
  }, []);

  const handleSelectKey = async () => {
    try {
      await requestApiKey();
      // Small delay to allow window state to update, or assume success as per instructions
      setHasKey(true);
      onReady();
    } catch (e) {
      console.error("Failed to select key", e);
    }
  };

  if (hasKey) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 backdrop-blur-sm">
      <div className="bg-[#1E1E1E] border border-gray-700 p-8 rounded-2xl max-w-md w-full text-center shadow-2xl">
        <h2 className="text-2xl font-bold text-white mb-4">API Key Required</h2>
        <p className="text-gray-400 mb-6">
          To generate high-quality 9:16 images with Gemini 3 Pro, you need to select a paid API key from a generic Google Cloud Project.
        </p>
        <div className="flex flex-col gap-4">
          <button
            onClick={handleSelectKey}
            className="w-full py-3 px-6 bg-shorts-red hover:bg-red-600 text-white font-semibold rounded-lg transition-colors"
          >
            Select API Key
          </button>
          <a
            href="https://ai.google.dev/gemini-api/docs/billing"
            target="_blank"
            rel="noopener noreferrer"
            className="text-sm text-shorts-accent hover:underline"
          >
            Read about Gemini API Billing
          </a>
        </div>
      </div>
    </div>
