/**
 * Analyzes a reference video to extract style and mood.
 * OPTIMIZED: Extracts a single frame client-side to speed up analysis significantly.
 */
export const analyzeVideoStyle = async (videoFile: File): Promise<string> => {
  const ai = getAiClient();

  // Extract a frame instead of uploading the whole video
  // This reduces upload size from MBs to KBs
  let base64Image: string;
  try {
     base64Image = await extractFrameFromVideo(videoFile);
  } catch (e) {
     console.warn("Frame extraction failed, falling back to full file (might be slow)", e);
     base64Image = await fileToBase64(videoFile);
  }

  const modelId = "gemini-3-flash-preview"; 

  const prompt = `
    Analyze this image frame from a video. Describe the visual style, color palette, lighting, 
    and overall "vibe" (e.g., cyberpunk, fast-paced, minimalist, cinematic). 
    Keep it concise (under 50 words). This description will be used to generate similar images.
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: "image/jpeg",
              data: base64Image,
            },
          },
          { text: prompt },
        ],
      },
    });
    return response.text || "Cinematic, high quality, trending on social media";
  } catch (error) {
    console.error("Video analysis failed", error);
    return "Cinematic, high quality";
  }
};

/**
 * Breaks down a script into scenes using JSON schema.
 */
export const generateScenesFromScript = async (script: string, styleContext: string): Promise<Scene[]> => {
  const ai = getAiClient();
  const modelId = "gemini-3-flash-preview";

  const prompt = `
    You are a professional storyboard artist for YouTube Shorts.
    Break down the following script into visual scenes. 
    Each scene should be 3-5 seconds long.

    The visual style should be: ${styleContext}.

    IMPORTANT: 
    - Generate as many scenes as required to cover the ENTIRE script.
    - Do not limit the number of scenes.
    - Ensure every sentence of the script is covered visually.

    Return a list of scenes. For each scene provide:
    1. The segment of the script being spoken.
    2. A detailed visual prompt to generate an image for this scene. 
       The visual prompt MUST include the style description.
       If the script mentions a character, refer to them as "the main character".
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: [
        { text: prompt },
        { text: `SCRIPT:\n${script}` }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              scriptSegment: { type: Type.STRING },
              visualPrompt: { type: Type.STRING, description: "Detailed image generation prompt" },
            },
            required: ["scriptSegment", "visualPrompt"],
          },
        },
      },
    });

    if (response.text) {
      const rawScenes = JSON.parse(response.text);
      return rawScenes.map((s: any, index: number) => ({
        id: `scene-${index}-${Date.now()}`,
        scriptSegment: s.scriptSegment,
        visualPrompt: s.visualPrompt,
        status: 'pending'
      }));
    }
    return [];
  } catch (error) {
    console.error("Scene generation failed", error);
    throw error;
  }
};

/**
 * Generates an image for a specific scene using the character reference.
 */
export const generateSceneImage = async (
  scene: Scene, 
  characterImageBase64: string | null
): Promise<string> => {
  const ai = getAiClient();
  const modelId = "gemini-3-pro-image-preview"; 

  const parts: any[] = [];

  // If we have a character reference, include it first
  if (characterImageBase64) {
    parts.push({
      inlineData: {
        mimeType: "image/png", 
        data: characterImageBase64,
      },
    });

    parts.push({
      text: `Generate a new scene based on this character. 
      IMPORTANT:
      1. Keep the character's facial features and clothing consistent if visible.
      2. If the reference image has a specific background or environment, TRY TO MAINTAIN that background style unless the scene description explicitly demands a different location.
      3. Scene description: ${scene.visualPrompt}.
      4. Ensure the aspect ratio fits a 9:16 frame naturally.`
    });
  } else {
    parts.push({ text: scene.visualPrompt });
  }

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: { parts },
      config: {
        imageConfig: {
          aspectRatio: "9:16",
          imageSize: "2K" 
        }
      }
    });

    // Extract image
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    throw new Error("No image data found in response");
  } catch (error) {
    console.error("Image generation failed", error);
    throw error;
  }
};

import React, { useState, useCallback } from 'react';
import { createRoot } from 'react-dom/client';
import { Scene, AppStep, GenerationConfig } from './types';
import { analyzeVideoStyle, generateScenesFromScript, generateSceneImage } from './services/geminiService';
import { cleanBase64, fileToBase64 } from './services/utils';
import { FileUpload } from './components/FileUpload';
import { SceneCard } from './components/SceneCard';
import { ApiKeyModal } from './components/ApiKeyModal';

const App: React.FC = () => {
  const [apiKeyReady, setApiKeyReady] = useState(false);
  const [step, setStep] = useState<AppStep>(AppStep.SETUP);
  const [loading, setLoading] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState('');

  // Inputs
  const [characterImage, setCharacterImage] = useState<string | null>(null);
  const [referenceVideo, setReferenceVideo] = useState<File | null>(null);
  const [referenceVideoUrl, setReferenceVideoUrl] = useState<string | null>(null);
  const [script, setScript] = useState('');

  // Results
  const [styleDescription, setStyleDescription] = useState<string>('');
  const [scenes, setScenes] = useState<Scene[]>([]);

  // Handlers
  const handleCharacterUpload = async (file: File) => {
    try {
      const base64 = await fileToBase64(file);
      setCharacterImage(base64);
    } catch (e) {
      alert("Error reading image file");
    }
  };

  const handleVideoUpload = (file: File) => {
    setReferenceVideo(file);
    setReferenceVideoUrl(URL.createObjectURL(file));
  };

  const startStoryboard = async () => {
    if (!script.trim()) return alert("Please enter a script");

    setLoading(true);
    setStep(AppStep.STORYBOARD);

    try {
      // 1. Analyze Video (if provided)
      let currentStyle = "Cinematic, high definition, youtube shorts aesthetic";
      if (referenceVideo) {
        setLoadingMessage('Analyzing video style...');
        // This now uses frame extraction for speed
        const videoStyle = await analyzeVideoStyle(referenceVideo);
        currentStyle = videoStyle;
        setStyleDescription(videoStyle);
      }

      // 2. Break down script
      setLoadingMessage('Creating storyboard scenes (this covers the full script)...');
      const generatedScenes = await generateScenesFromScript(script, currentStyle);
      setScenes(generatedScenes);

      setLoading(false);
    } catch (error) {
      console.error(error);
      alert("Failed to generate storyboard. See console for details.");
      setStep(AppStep.SETUP);
      setLoading(false);
    }
  };

  const generateAllImages = async () => {
    if (scenes.length === 0) return;

    // Process parallel for speed
    const newScenes = [...scenes];

    // Set all to generating
    setScenes(prev => prev.map(s => s.status === 'completed' ? s : { ...s, status: 'generating' }));

    const cleanCharImage = characterImage ? cleanBase64(characterImage) : null;

    // We'll update state as each one finishes
    for (let i = 0; i < newScenes.length; i++) {
        const scene = newScenes[i];
        if (scene.status === 'completed') continue;

        try {
            const base64Image = await generateSceneImage(scene, cleanCharImage);

            setScenes(current => current.map(s => {
                if (s.id === scene.id) {
                    return { ...s, status: 'completed', imageUrl: base64Image };
                }
                return s;
            }));
        } catch (e) {
            console.error(`Failed scene ${i}`, e);
            setScenes(current => current.map(s => {
                if (s.id === scene.id) {
                    return { ...s, status: 'error' };
                }
                return s;
            }));
        }
    }
  };

  const generateSingleScene = async (targetScene: Scene) => {
     setScenes(current => current.map(s => s.id === targetScene.id ? { ...s, status: 'generating' } : s));
     const cleanCharImage = characterImage ? cleanBase64(characterImage) : null;

     try {
        const base64Image = await generateSceneImage(targetScene, cleanCharImage);
        setScenes(current => current.map(s => {
            if (s.id === targetScene.id) {
                return { ...s, status: 'completed', imageUrl: base64Image };
            }
            return s;
        }));
     } catch (e) {
        setScenes(current => current.map(s => s.id === targetScene.id ? { ...s, status: 'error' } : s));
     }
  };

  const downloadAllImages = () => {
    let downloadCount = 0;
    scenes.forEach((scene, index) => {
      if (scene.imageUrl) {
        downloadCount++;
        const link = document.createElement('a');
        link.href = scene.imageUrl;
        // Pad index for easier sorting
        const paddedIndex = (index + 1).toString().padStart(2, '0');
        link.download = `scene_${paddedIndex}.png`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
      }
    });

    if (downloadCount === 0) {
      alert("No generated images to download yet!");
    }
  };

  if (!apiKeyReady) {
      return <ApiKeyModal onReady={() => setApiKeyReady(true)} />;
  }

  return (
    <div className="min-h-screen bg-[#0F0F0F] text-white font-sans selection:bg-shorts-red selection:text-white">
      {/* Header */}
      <header className="fixed top-0 left-0 right-0 z-40 bg-[#0F0F0F]/90 backdrop-blur-md border-b border-gray-800 h-16 flex items-center px-6 justify-between">
        <div className="flex items-center gap-2">
           <div className="w-8 h-8 bg-shorts-red rounded-lg flex items-center justify-center font-bold text-white">S</div>
           <h1 className="text-xl font-bold tracking-tight">Shorts AI <span className="text-gray-500 font-normal">Storyboarder</span></h1>
        </div>

        <div className="flex gap-4">
          {step === AppStep.STORYBOARD && (
            <>
              <button 
                onClick={downloadAllImages}
                className="text-sm font-semibold text-shorts-accent hover:text-blue-400 transition-colors flex items-center gap-1"
              >
                <span>⬇️</span> Download Images
              </button>
              <button 
                onClick={() => setStep(AppStep.SETUP)}
                className="text-sm text-gray-400 hover:text-white transition-colors"
              >
                Start Over
              </button>
            </>
          )}
        </div>
      </header>

      <main className="pt-24 pb-20 px-4 max-w-7xl mx-auto">

        {step === AppStep.SETUP && (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 animate-fade-in">
            {/* Left Col: Inputs */}
            <div className="space-y-8">
              <div className="space-y-2">
                <h2 className="text-3xl font-bold">Create your next viral Short.</h2>
                <p className="text-gray-400">Import your character, define a style, and let AI visualize your script scene by scene.</p>
              </div>

              <div className="grid grid-cols-2 gap-6">
                <FileUpload 
                  label="Character Reference (Optional)" 
                  accept="image/*" 
                  onFileSelect={handleCharacterUpload} 
                  previewUrl={characterImage || undefined}
                  icon={<span className="text-3xl">👤</span>}
                />
                <FileUpload 
                  label="Style Reference Video (Optional)" 
                  accept="video/*" 
                  onFileSelect={handleVideoUpload} 
                  previewUrl={referenceVideoUrl || undefined}
                  isVideo={true}
                  icon={<span className="text-3xl">🎥</span>}
                />
              </div>
            </div>

            {/* Right Col: Script & Action */}
            <div className="flex flex-col h-full space-y-6">
               <label className="block text-sm font-medium text-gray-400">Video Script</label>
               <textarea
                 className="flex-1 w-full bg-[#1E1E1E] border border-gray-700 rounded-xl p-6 text-lg leading-relaxed focus:outline-none focus:ring-2 focus:ring-shorts-red resize-none transition-all placeholder-gray-600"
                 placeholder="Paste your YouTube Short script here... (e.g., 'Did you know that octopuses have three hearts? It's true! Two pump blood to the gills...')"
                 value={script}
                 onChange={(e) => setScript(e.target.value)}
               />

               <button
                 onClick={startStoryboard}
                 disabled={loading || !script.trim()}
                 className={`
                    w-full py-4 rounded-xl font-bold text-lg shadow-lg flex items-center justify-center gap-3 transition-all
                    ${loading || !script.trim() ? 'bg-gray-800 text-gray-500 cursor-not-allowed' : 'bg-white text-black hover:bg-shorts-red hover:text-white hover:scale-[1.02]'}
                 `}
               >
                 {loading ? (
                   <>
                     <svg className="animate-spin h-5 w-5" viewBox="0 0 24 24">
                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none"></circle>
                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                     </svg>
                     <span>{loadingMessage}</span>
                   </>
                 ) : (
                   <>
                     <span>Generate Storyboard</span>
                     <span>→</span>
                   </>
                 )}
               </button>
            </div>
          </div>
        )}

        {step === AppStep.STORYBOARD && (
           <div className="space-y-8 animate-fade-in-up">
              <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 border-b border-gray-800 pb-6">
                 <div>
                    <h2 className="text-2xl font-bold">Storyboard</h2>
                    <p className="text-gray-400 text-sm mt-1">
                       {scenes.length} Scenes • Style: <span className="text-shorts-accent">{styleDescription || 'Default'}</span>
                    </p>
                 </div>
                 <button
                    onClick={generateAllImages}
                    className="bg-shorts-red hover:bg-red-600 text-white px-8 py-3 rounded-full font-bold shadow-lg shadow-red-900/20 transition-all flex items-center gap-2"
                 >
                    <span className="text-xl">✨</span> Generate All Images
                 </button>
              </div>

              <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-6">
                  {scenes.map((scene, idx) => (
                    <SceneCard 
                      key={scene.id} 
                      scene={scene} 
                      index={idx} 
                      onRegenerate={generateSingleScene} 
                    />
                  ))}
              </div>
           </div>
        )}
      </main>
    </div>
  );
};

const root = createRoot(document.getElementById('root')!);
root.render(<App />);

