export const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      // Remove data URL prefix (e.g., "data:image/jpeg;base64,")
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = (error) => reject(error);
  });
};

export const cleanBase64 = (dataUrl: string): string => {
  if (dataUrl.includes(',')) {
    return dataUrl.split(',')[1];
  }
  return dataUrl;
};

export const extractFrameFromVideo = (videoFile: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    // 1. Timeout safety to prevent hanging
    const timeout = setTimeout(() => {
      reject(new Error("Video frame extraction timed out"));
      cleanup();
    }, 4000);

    const url = URL.createObjectURL(videoFile);
    const video = document.createElement("video");

    const cleanup = () => {
      clearTimeout(timeout);
      URL.revokeObjectURL(url);
      video.remove();
    };

    video.src = url;
    video.muted = true;
    video.playsInline = true;
    video.crossOrigin = "anonymous";

    // 2. Capture extremely early to speed up seek time
    const captureTime = 0.1; 

    video.onloadeddata = () => {
      video.currentTime = Math.min(captureTime, video.duration);
    };

    video.onseeked = () => {
      const canvas = document.createElement("canvas");

      // 3. Resize to small dimensions for fast processing and upload
      const maxDim = 512;
      let width = video.videoWidth;
      let height = video.videoHeight;

      // Maintain aspect ratio but scale down
      if (width > maxDim || height > maxDim) {
        const ratio = width / height;
        if (ratio > 1) {
            width = maxDim;
            height = maxDim / ratio;
        } else {
            height = maxDim;
            width = maxDim * ratio;
        }
      }

      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext("2d");

      if (ctx) {
        ctx.drawImage(video, 0, 0, width, height);
        // 4. Low quality JPEG for efficient API payload
        const dataUrl = canvas.toDataURL("image/jpeg", 0.6);
        resolve(dataUrl.split(",")[1]);
      } else {
        reject(new Error("Canvas init failed"));
      }
      cleanup();
    };

    video.onerror = (e) => {
      reject(e);
      cleanup();
    };
  });
};

import { GoogleGenAI, Type } from "@google/genai";
import { Scene } from "../types";
import { fileToBase64, extractFrameFromVideo } from "./utils";

// Initialize Gemini Client
// We use a getter to ensure we pick up the key if it changes (e.g. via selection)
const getAiClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

export const checkApiKey = async (): Promise<boolean> => {
  if (window.aistudio && window.aistudio.hasSelectedApiKey) {
     return await window.aistudio.hasSelectedApiKey();
  }
  return true; // Fallback if not in the specific environment
};

export const requestApiKey = async () => {
  if (window.aistudio && window.aistudio.openSelectKey) {
    await window.aistudio.openSelectKey();
  }
};

/**
 * Analyzes a reference video to extract style and mood.
 * OPTIMIZED: Extracts a single frame client-side.
 * Handles fallbacks gracefully to avoid long upload times.
 */
export const analyzeVideoStyle = async (videoFile: File): Promise<string> => {
  const ai = getAiClient();

  let base64Image: string | null = null;

  try {
     // Try fast frame extraction
     base64Image = await extractFrameFromVideo(videoFile);
  } catch (e) {
     console.warn("Frame extraction failed", e);

     // Only fallback to full upload if video is small (< 10MB)
     // Uploading large videos causes the "taking too long" user issue.
     if (videoFile.size < 10 * 1024 * 1024) {
        try {
          base64Image = await fileToBase64(videoFile);
        } catch (err) {
          console.warn("Fallback upload failed", err);
        }
     }
  }

  // If extraction failed and file was too big, skip analysis
  if (!base64Image) {
    console.warn("Skipping video analysis due to size/extraction issues.");
    return "Cinematic, high definition, viral youtube shorts aesthetic, dynamic lighting";
  }

  const modelId = "gemini-3-flash-preview"; 

  const prompt = `
    Analyze this image frame from a video. Describe the visual style, color palette, lighting, 
    and overall "vibe" (e.g., cyberpunk, fast-paced, minimalist, cinematic). 
    Keep it concise (under 50 words). This description will be used to generate similar images.
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: "image/jpeg",
              data: base64Image,
            },
          },
          { text: prompt },
        ],
      },
    });
    return response.text || "Cinematic, high quality, trending on social media";
  } catch (error) {
    console.error("Video analysis failed", error);
    return "Cinematic, high quality";
  }
};

/**
 * Breaks down a script into scenes using JSON schema.
 */
export const generateScenesFromScript = async (script: string, styleContext: string): Promise<Scene[]> => {
  const ai = getAiClient();
  const modelId = "gemini-3-flash-preview";

  const prompt = `
    You are an expert Director of Photography and Storyboard Artist for viral YouTube Shorts.
    Your goal is to create a HIGH RETENTION, ENTERTAINING visual flow.

    Break down the following script into visual scenes. 

    CRITICAL INSTRUCTIONS FOR "BORING" PREVENTION:
    1. AVOID generic flat shots. Use DYNAMIC ANGLES (Low angle, Dutch angle, Bird's eye, Extreme Close-up).
    2. Focus on ACTION and EMOTION. If the script is informational, visualize the concept metaphorically or with high drama.
    3. Vary the pacing and composition between scenes.
    4. The visual style context is: ${styleContext}.

    IMPORTANT: 
    - Generate as many scenes as required to cover the ENTIRE script.
    - Do not limit the number of scenes.

    Return a list of scenes. For each scene provide:
    1. The segment of the script being spoken.
    2. A detailed visual prompt. MUST include specific camera instructions (e.g., "Wide shot from below," "Extreme close up on eyes").
       If the script mentions a character, refer to them as "the main character".
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: [
        { text: prompt },
        { text: `SCRIPT:\n${script}` }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              scriptSegment: { type: Type.STRING },
              visualPrompt: { type: Type.STRING, description: "Detailed, dynamic image generation prompt with camera angles" },
            },
            required: ["scriptSegment", "visualPrompt"],
          },
        },
      },
    });

    if (response.text) {
      const rawScenes = JSON.parse(response.text);
      return rawScenes.map((s: any, index: number) => ({
        id: `scene-${index}-${Date.now()}`,
        scriptSegment: s.scriptSegment,
        visualPrompt: s.visualPrompt,
        status: 'pending'
      }));
    }
    return [];
  } catch (error) {
    console.error("Scene generation failed", error);
    throw error;
  }
};

/**
 * Generates an image for a specific scene using the character reference.
 */
export const generateSceneImage = async (
  scene: Scene, 
  characterImageBase64: string | null
): Promise<string> => {
  const ai = getAiClient();
  const modelId = "gemini-3-pro-image-preview"; 

  const parts: any[] = [];

  // If we have a character reference, include it first
  if (characterImageBase64) {
    parts.push({
      inlineData: {
        mimeType: "image/png", 
        data: characterImageBase64,
      },
    });

    parts.push({
      text: `Generate a new scene based on this source image.

      CRITICAL INSTRUCTIONS:
      1. USE THE SOURCE IMAGE'S BACKGROUND. Do not invent a new location. The character should appear to be in the EXACT SAME PLACE/ENVIRONMENT as the source photo.
      2. Keep the character's facial features and clothing consistent.
      3. Apply the following action/composition: ${scene.visualPrompt}
      4. Ensure the aspect ratio fits a 9:16 frame naturally.
      5. Make it look like a high-budget movie still, not a generic cartoon.`
    });
  } else {
    parts.push({ 
      text: `Create a cinematic, 9:16 vertical image for a YouTube Short.
      Scene description: ${scene.visualPrompt}.
      Style: High quality, dramatic lighting, detailed texture.` 
    });
  }

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: { parts },
      config: {
        imageConfig: {
          aspectRatio: "9:16",
          imageSize: "2K" 
        }
      }
    });

    // Extract image
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    throw new Error("No image data found in response");
  } catch (error) {
    console.error("Image generation failed", error);
    throw error;
  }
};

