import { GoogleGenAI, Type } from "@google/genai";
import { Scene } from "../types";
import { fileToBase64, extractFrameFromVideo } from "./utils";

// Initialize Gemini Client
// We use a getter to ensure we pick up the key if it changes (e.g. via selection)
const getAiClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

export const checkApiKey = async (): Promise<boolean> => {
  if (window.aistudio && window.aistudio.hasSelectedApiKey) {
     return await window.aistudio.hasSelectedApiKey();
  }
  return true; // Fallback if not in the specific environment
};

export const requestApiKey = async () => {
  if (window.aistudio && window.aistudio.openSelectKey) {
    await window.aistudio.openSelectKey();
  }
};

/**
 * Analyzes a reference video to extract style and mood.
 * OPTIMIZED: Extracts a single frame client-side.
 * Handles fallbacks gracefully to avoid long upload times.
 */
export const analyzeVideoStyle = async (videoFile: File): Promise<string> => {
  const ai = getAiClient();

  let base64Image: string | null = null;

  try {
     // Try fast frame extraction
     base64Image = await extractFrameFromVideo(videoFile);
  } catch (e) {
     console.warn("Frame extraction failed", e);

     // Only fallback to full upload if video is small (< 10MB)
     // Uploading large videos causes the "taking too long" user issue.
     if (videoFile.size < 10 * 1024 * 1024) {
        try {
          base64Image = await fileToBase64(videoFile);
        } catch (err) {
          console.warn("Fallback upload failed", err);
        }
     }
  }

  // If extraction failed and file was too big, skip analysis
  if (!base64Image) {
    console.warn("Skipping video analysis due to size/extraction issues.");
    return "Cinematic, high definition, viral youtube shorts aesthetic, dynamic lighting";
  }

  const modelId = "gemini-3-flash-preview"; 

  const prompt = `
    Analyze this image frame from a video. Describe the visual style, color palette, lighting, 
    and overall "vibe" (e.g., cyberpunk, fast-paced, minimalist, cinematic). 
    Keep it concise (under 50 words). This description will be used to generate similar images.
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: "image/jpeg",
              data: base64Image,
            },
          },
          { text: prompt },
        ],
      },
    });
    return response.text || "Cinematic, high quality, trending on social media";
  } catch (error) {
    console.error("Video analysis failed", error);
    return "Cinematic, high quality";
  }
};

/**
 * Breaks down a script into scenes using JSON schema.
 */
export const generateScenesFromScript = async (
  script: string, 
  styleContext: string,
  pacing: 'fast' | 'slow' = 'fast'
): Promise<Scene[]> => {
  const ai = getAiClient();
  const modelId = "gemini-3-flash-preview";

  const pacingInstructions = pacing === 'fast' 
    ? "PACING: FAST / VIRAL. Break the script into many short, dynamic scenes. Use frequent cuts (every 2-4 seconds) to maintain high retention." 
    : "PACING: MINIMAL / ECONOMICAL. Consolidate the script into the FEWEST number of scenes possible. Group long segments of text into single scenes. Only cut if the visual context MUST change.";

  const prompt = `
    You are an expert Director of Photography and Storyboard Artist for viral YouTube Shorts.
    Your goal is to create a visual flow based on the requested pacing strategy.

    Break down the following script into visual scenes. 

    ${pacingInstructions}

    CRITICAL INSTRUCTIONS FOR VISUALS:
    1. AVOID generic flat shots. Use DYNAMIC ANGLES (Low angle, Dutch angle, Bird's eye, Extreme Close-up).
    2. Focus on ACTION and EMOTION. If the script is informational, visualize the concept metaphorically or with high drama.
    3. The visual style context is: ${styleContext}.

    IMPORTANT: 
    - Generate scenes to cover the ENTIRE script.
    ${pacing === 'fast' ? '- Do not limit the number of scenes.' : '- STRICTLY LIMIT the number of scenes to the absolute minimum.'}

    Return a list of scenes. For each scene provide:
    1. The segment of the script being spoken.
    2. A detailed visual prompt. MUST include specific camera instructions (e.g., "Wide shot from below," "Extreme close up on eyes").
       If the script mentions a character, refer to them as "the main character".
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: [
        { text: prompt },
        { text: `SCRIPT:\n${script}` }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              scriptSegment: { type: Type.STRING },
              visualPrompt: { type: Type.STRING, description: "Detailed, dynamic image generation prompt with camera angles" },
            },
            required: ["scriptSegment", "visualPrompt"],
          },
        },
      },
    });

    if (response.text) {
      const rawScenes = JSON.parse(response.text);
      return rawScenes.map((s: any, index: number) => ({
        id: `scene-${index}-${Date.now()}`,
        scriptSegment: s.scriptSegment,
        visualPrompt: s.visualPrompt,
        status: 'pending'
      }));
    }
    return [];
  } catch (error) {
    console.error("Scene generation failed", error);
    throw error;
  }
};

/**
 * Generates an image for a specific scene using the character reference (image or text).
 */
export const generateSceneImage = async (
  scene: Scene, 
  characterImageBase64: string | null,
  characterDescription: string | null = null
): Promise<string> => {
  const ai = getAiClient();
  const modelId = "gemini-3-pro-image-preview"; 

  const parts: any[] = [];

  // If we have a character reference image
  if (characterImageBase64) {
    parts.push({
      inlineData: {
        mimeType: "image/png", 
        data: characterImageBase64,
      },
    });

    parts.push({
      text: `Generate a new scene based on this source image.

      CRITICAL INSTRUCTIONS:
      1. USE THE SOURCE IMAGE'S BACKGROUND. Do not invent a new location. The character should appear to be in the EXACT SAME PLACE/ENVIRONMENT as the source photo.
      2. Keep the character's facial features and clothing consistent.
      3. Apply the following action/composition: ${scene.visualPrompt}
      4. Ensure the aspect ratio fits a 9:16 frame naturally.
      5. Make it look like a high-budget movie still, not a generic cartoon.`
    });
  } else {
    // No image, use text-based generation logic
    let prompt = `Create a cinematic, 9:16 vertical image for a YouTube Short.`;

    if (characterDescription) {
        prompt += `\n\nCHARACTER & SETTING INSTRUCTIONS: ${characterDescription}\nIMPORTANT: Maintain the character and setting details described above.`;
    }

    prompt += `\n\nSCENE ACTION/COMPOSITION: ${scene.visualPrompt}.
    Style: High quality, dramatic lighting, detailed texture.`;

    parts.push({ text: prompt });
  }

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: { parts },
      config: {
        imageConfig: {
          aspectRatio: "9:16",
          imageSize: "2K" 
        }
      }
    });

    // Extract image
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    throw new Error("No image data found in response");
  } catch (error) {
    console.error("Image generation failed", error);
    throw error;
  }
};

import React, { useState, useCallback } from 'react';
import { createRoot } from 'react-dom/client';
import { Scene, AppStep, GenerationConfig } from './types';
import { analyzeVideoStyle, generateScenesFromScript, generateSceneImage } from './services/geminiService';
import { cleanBase64, fileToBase64 } from './services/utils';
import { FileUpload } from './components/FileUpload';
import { SceneCard } from './components/SceneCard';
import { ApiKeyModal } from './components/ApiKeyModal';

const App: React.FC = () => {
  const [apiKeyReady, setApiKeyReady] = useState(false);
  const [step, setStep] = useState<AppStep>(AppStep.SETUP);
  const [loading, setLoading] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState('');
  const [generationProgress, setGenerationProgress] = useState<{ completed: number; total: number } | null>(null);

  // Inputs
  const [characterInputMode, setCharacterInputMode] = useState<'upload' | 'text'>('upload');
  const [characterImage, setCharacterImage] = useState<string | null>(null);
  const [characterDescription, setCharacterDescription] = useState('');

  const [referenceVideo, setReferenceVideo] = useState<File | null>(null);
  const [referenceVideoUrl, setReferenceVideoUrl] = useState<string | null>(null);
  const [script, setScript] = useState('');
  const [pacing, setPacing] = useState<'fast' | 'slow'>('fast');

  // New Style State
  const [stylePrompt, setStylePrompt] = useState("Cinematic, high definition, viral youtube shorts aesthetic, dynamic lighting");
  const [isAnalyzingStyle, setIsAnalyzingStyle] = useState(false);

  // Results
  const [styleDescription, setStyleDescription] = useState<string>('');
  const [scenes, setScenes] = useState<Scene[]>([]);

  // Handlers
  const handleCharacterUpload = async (file: File) => {
    try {
      const base64 = await fileToBase64(file);
      setCharacterImage(base64);
    } catch (e) {
      alert("Error reading image file");
    }
  };

  const handleVideoUpload = async (file: File) => {
    setReferenceVideo(file);
    setReferenceVideoUrl(URL.createObjectURL(file));

    // Immediate analysis when video is uploaded
    setIsAnalyzingStyle(true);
    try {
        const analyzedStyle = await analyzeVideoStyle(file);
        setStylePrompt(analyzedStyle);
    } catch (e) {
        console.error("Style analysis failed", e);
    } finally {
        setIsAnalyzingStyle(false);
    }
  };

  const startStoryboard = async () => {
    if (!script.trim()) return alert("Please enter a script");

    setLoading(true);
    setStep(AppStep.STORYBOARD);

    try {
      // 1. Use the user-defined style prompt directly
      const currentStyle = stylePrompt;
      setStyleDescription(currentStyle);

      // 2. Break down script
      setLoadingMessage('Director AI is planning your shots...');
      const generatedScenes = await generateScenesFromScript(script, currentStyle, pacing);
      setScenes(generatedScenes);

      setLoading(false);
    } catch (error) {
      console.error(error);
      alert("Failed to generate storyboard. See console for details.");
      setStep(AppStep.SETUP);
      setLoading(false);
    }
  };

  const generateAllImages = async () => {
    const scenesToGenerate = scenes.filter(s => s.status !== 'completed');
    if (scenesToGenerate.length === 0) {
        alert("All scenes are already generated!");
        return;
    }

    setGenerationProgress({ completed: 0, total: scenesToGenerate.length });

    // Set all to generating so spinners appear on cards immediately
    setScenes(prev => prev.map(s => s.status === 'completed' ? s : { ...s, status: 'generating' }));

    const cleanCharImage = (characterInputMode === 'upload' && characterImage) ? cleanBase64(characterImage) : null;
    const charDesc = (characterInputMode === 'text') ? characterDescription : null;

    // Iterate through original scenes to preserve order, but skip completed ones
    let completedCount = 0;

    for (const scene of scenes) {
        if (scene.status === 'completed') continue;

        try {
            const base64Image = await generateSceneImage(scene, cleanCharImage, charDesc);

            setScenes(current => current.map(s => {
                if (s.id === scene.id) {
                    return { ...s, status: 'completed', imageUrl: base64Image };
                }
                return s;
            }));
        } catch (e) {
            console.error(`Failed scene ${scene.id}`, e);
            setScenes(current => current.map(s => {
                if (s.id === scene.id) {
                    return { ...s, status: 'error' };
                }
                return s;
            }));
        } finally {
            completedCount++;
            setGenerationProgress({ completed: completedCount, total: scenesToGenerate.length });
        }
    }

    // Clear progress after short delay
    setTimeout(() => setGenerationProgress(null), 1000);
  };

  const generateSingleScene = async (targetScene: Scene) => {
     setScenes(current => current.map(s => s.id === targetScene.id ? { ...s, status: 'generating' } : s));

     const cleanCharImage = (characterInputMode === 'upload' && characterImage) ? cleanBase64(characterImage) : null;
     const charDesc = (characterInputMode === 'text') ? characterDescription : null;

     try {
        const base64Image = await generateSceneImage(targetScene, cleanCharImage, charDesc);
        setScenes(current => current.map(s => {
            if (s.id === targetScene.id) {
                return { ...s, status: 'completed', imageUrl: base64Image };
            }
            return s;
        }));
     } catch (e) {
        setScenes(current => current.map(s => s.id === targetScene.id ? { ...s, status: 'error' } : s));
     }
  };

  const downloadAllImages = async () => {
    const completedScenes = scenes.filter(s => s.imageUrl);

    if (completedScenes.length === 0) {
      alert("No generated images to download yet! Click 'Generate All Images' first.");
      return;
    }

    if (completedScenes.length < scenes.length) {
       const confirm = window.confirm(`Only ${completedScenes.length} of ${scenes.length} scenes are ready. Download them anyway?`);
       if (!confirm) return;
    }

    // Using a loop with delay to prevent browser blocking multiple downloads
    for (let i = 0; i < completedScenes.length; i++) {
      const scene = completedScenes[i];
      if (scene.imageUrl) {
        const link = document.createElement('a');
        link.href = scene.imageUrl;
        // Pad index for easier sorting in file explorer
        const paddedIndex = (i + 1).toString().padStart(2, '0');
        link.download = `scene_${paddedIndex}.png`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);

        // Small delay to ensure browser acknowledges each download action
        await new Promise(resolve => setTimeout(resolve, 500));
      }
    }
  };

  if (!apiKeyReady) {
      return <ApiKeyModal onReady={() => setApiKeyReady(true)} />;
  }

  return (
    <div className="min-h-screen bg-[#0F0F0F] text-white font-sans selection:bg-shorts-red selection:text-white">
      {/* Header */}
      <header className="fixed top-0 left-0 right-0 z-40 bg-[#0F0F0F]/90 backdrop-blur-md border-b border-gray-800 h-16 flex items-center px-6 justify-between">
        <div className="flex items-center gap-2">
           <div className="w-8 h-8 bg-shorts-red rounded-lg flex items-center justify-center font-bold text-white">S</div>
           <h1 className="text-xl font-bold tracking-tight">Shorts AI <span className="text-gray-500 font-normal">Storyboarder</span></h1>
        </div>

        <div className="flex gap-4">
          {step === AppStep.STORYBOARD && (
            <>
              <button 
                onClick={downloadAllImages}
                className="text-sm font-semibold text-shorts-accent hover:text-blue-400 transition-colors flex items-center gap-1"
                disabled={!!generationProgress}
              >
                <span>⬇️</span> Download Images
              </button>
              <button 
                onClick={() => setStep(AppStep.SETUP)}
                className="text-sm text-gray-400 hover:text-white transition-colors"
                disabled={!!generationProgress}
              >
                Start Over
              </button>
            </>
          )}
        </div>
      </header>

      <main className="pt-24 pb-20 px-4 max-w-7xl mx-auto">

        {step === AppStep.SETUP && (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 animate-fade-in">
            {/* Left Col: Inputs */}
            <div className="space-y-8">
              <div className="space-y-2">
                <h2 className="text-3xl font-bold">Create your next viral Short.</h2>
                <p className="text-gray-400">Import your character, define a style, and let AI visualize your script scene by scene.</p>
              </div>

              <div className="grid grid-cols-2 gap-6">
                {/* Character Input Section with Toggle */}
                <div className="flex flex-col gap-3">
                   <div className="flex items-center justify-between">
                      <label className="text-sm font-medium text-gray-400">Character & Background</label>
                      <div className="flex bg-[#181818] rounded-lg p-1 border border-gray-700">
                          <button 
                             onClick={() => setCharacterInputMode('upload')}
                             className={`px-3 py-1 text-xs font-medium rounded-md transition-all ${characterInputMode === 'upload' ? 'bg-gray-700 text-white' : 'text-gray-400 hover:text-gray-200'}`}
                          >Upload</button>
                          <button 
                             onClick={() => setCharacterInputMode('text')}
                             className={`px-3 py-1 text-xs font-medium rounded-md transition-all ${characterInputMode === 'text' ? 'bg-gray-700 text-white' : 'text-gray-400 hover:text-gray-200'}`}
                          >Describe</button>
                      </div>
                   </div>

                   {characterInputMode === 'upload' ? (
                      <div className="h-full">
                         <FileUpload 
                           label="" 
                           accept="image/*" 
                           onFileSelect={handleCharacterUpload} 
                           previewUrl={characterImage || undefined}
                           icon={<span className="text-3xl">👤</span>}
                         />
                      </div>
                   ) : (
                      <div className="w-full aspect-[9/16] max-h-64 sm:max-h-80">
                         <textarea 
                             className="w-full h-full bg-[#181818] border border-gray-700 rounded-xl p-4 text-sm focus:outline-none focus:ring-2 focus:ring-shorts-red resize-none placeholder-gray-600 text-gray-200 leading-relaxed"
                             placeholder="Describe your character and setting in detail...&#10;&#10;Example:&#10;'A futuristic cyberpunk samurai with a glowing blue katana. He is standing in a rainy neon city alleyway at night. He wears a matte black tactical vest and a traditional straw hat.'"
                             value={characterDescription}
                             onChange={(e) => setCharacterDescription(e.target.value)}
                         />
                      </div>
                   )}
                </div>

                <div className="flex flex-col gap-3">
                    <div className="h-[29px]"></div> {/* Spacer to align with label row if needed, or just let generic layout handle it */}
                    <FileUpload 
                      label="Style Reference Video (Optional)" 
                      accept="video/*" 
                      onFileSelect={handleVideoUpload} 
                      previewUrl={referenceVideoUrl || undefined}
                      isVideo={true}
                      icon={<span className="text-3xl">🎥</span>}
                    />
                </div>
              </div>

              {/* Style Editor */}
              <div className="space-y-3">
                 <div className="flex items-center justify-between">
                    <label className="text-sm font-medium text-gray-400">Visual Style & Art Direction</label>
                    {isAnalyzingStyle && (
                        <span className="text-xs font-semibold text-shorts-accent animate-pulse flex items-center gap-1">
                            <span className="w-2 h-2 rounded-full bg-shorts-accent"></span>
                            Extracting style from video...
                        </span>
                    )}
                 </div>
                 <textarea
                    className="w-full bg-[#181818] border border-gray-700 rounded-xl p-4 text-sm leading-relaxed text-gray-200 focus:outline-none focus:ring-2 focus:ring-shorts-red resize-none transition-all placeholder-gray-600"
                    rows={3}
                    placeholder="Describe the look and feel (e.g., 'Cyberpunk city, neon lights, high contrast, 3D render')"
                    value={stylePrompt}
                    onChange={(e) => setStylePrompt(e.target.value)}
                 />
                 <p className="text-xs text-gray-500">
                    This prompt will control the look of every generated scene. Upload a video above to auto-generate this description.
                 </p>
              </div>
            </div>

            {/* Right Col: Script & Action */}
            <div className="flex flex-col h-full space-y-6">
               <label className="block text-sm font-medium text-gray-400">Video Script</label>
               <textarea
                 className="flex-1 w-full bg-[#1E1E1E] border border-gray-700 rounded-xl p-6 text-lg leading-relaxed focus:outline-none focus:ring-2 focus:ring-shorts-red resize-none transition-all placeholder-gray-600"
                 placeholder="Paste your YouTube Short script here... (e.g., 'Did you know that octopuses have three hearts? It's true! Two pump blood to the gills...')"
                 value={script}
                 onChange={(e) => setScript(e.target.value)}
               />

               {/* Pacing Controls */}
               <div className="bg-[#181818] p-4 rounded-xl border border-gray-700 space-y-3">
                  <label className="text-sm font-medium text-gray-400 block">Pacing & Scene Count</label>
                  <div className="flex gap-4">
                    <button
                      onClick={() => setPacing('fast')}
                      className={`flex-1 py-3 px-4 rounded-lg text-sm font-medium transition-all border text-left flex flex-col gap-1 ${pacing === 'fast' ? 'bg-shorts-red/10 border-shorts-red text-white' : 'bg-[#252525] border-transparent text-gray-400 hover:bg-[#303030]'}`}
                    >
                      <span className="flex items-center gap-2">🚀 Fast (Viral)</span>
                      <span className="text-xs opacity-60 font-normal">More scenes, higher retention. Best for engagement.</span>
                    </button>
                    <button
                      onClick={() => setPacing('slow')}
                      className={`flex-1 py-3 px-4 rounded-lg text-sm font-medium transition-all border text-left flex flex-col gap-1 ${pacing === 'slow' ? 'bg-shorts-red/10 border-shorts-red text-white' : 'bg-[#252525] border-transparent text-gray-400 hover:bg-[#303030]'}`}
                    >
                      <span className="flex items-center gap-2">📉 Minimal (Budget)</span>
                      <span className="text-xs opacity-60 font-normal">Fewest scenes possible. Good for simple storytelling.</span>
                    </button>
                  </div>
               </div>

               <button
                 onClick={startStoryboard}
                 disabled={loading || !script.trim()}
                 className={`
                    w-full py-4 rounded-xl font-bold text-lg shadow-lg flex items-center justify-center gap-3 transition-all
                    ${loading || !script.trim() ? 'bg-gray-800 text-gray-500 cursor-not-allowed' : 'bg-white text-black hover:bg-shorts-red hover:text-white hover:scale-[1.02]'}
                 `}
               >
                 {loading ? (
                   <>
                     <svg className="animate-spin h-5 w-5" viewBox="0 0 24 24">
                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none"></circle>
                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                     </svg>
                     <span>{loadingMessage}</span>
                   </>
                 ) : (
                   <>
                     <span>Generate Storyboard</span>
                     <span>→</span>
                   </>
                 )}
               </button>
            </div>
          </div>
        )}

        {step === AppStep.STORYBOARD && (
           <div className="space-y-8 animate-fade-in-up">
              <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 border-b border-gray-800 pb-6">
                 <div>
                    <h2 className="text-2xl font-bold">Storyboard</h2>
                    <p className="text-gray-400 text-sm mt-1 max-w-xl truncate">
                       {scenes.length} Scenes • Style: <span className="text-shorts-accent">{styleDescription || 'Default'}</span>
                    </p>
                 </div>

                 {generationProgress ? (
                   <div className="flex items-center gap-4 bg-[#1E1E1E] border border-gray-700 px-6 py-3 rounded-full shadow-lg">
                      <div className="w-5 h-5 border-2 border-shorts-red border-t-transparent rounded-full animate-spin"></div>
                      <div className="flex flex-col">
                        <span className="text-sm font-semibold text-white">
                          Generating {generationProgress.completed < generationProgress.total ? generationProgress.completed + 1 : generationProgress.total} of {generationProgress.total}
                        </span>
                        <div className="w-32 h-1 bg-gray-700 rounded-full mt-1.5 overflow-hidden">
                          <div 
                            className="h-full bg-shorts-red transition-all duration-300 ease-out"
                            style={{ width: `${(generationProgress.completed / generationProgress.total) * 100}%` }}
                          />
                        </div>
                      </div>
                   </div>
                 ) : (
                   <button
                      onClick={generateAllImages}
                      className="bg-shorts-red hover:bg-red-600 text-white px-8 py-3 rounded-full font-bold shadow-lg shadow-red-900/20 transition-all flex items-center gap-2"
                   >
                      <span className="text-xl">✨</span> Generate All Images
                   </button>
                 )}
              </div>

              <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-6">
                  {scenes.map((scene, idx) => (
                    <SceneCard 
                      key={scene.id} 
                      scene={scene} 
                      index={idx} 
                      onRegenerate={generateSingleScene} 
                    />
                  ))}
              </div>
           </div>
        )}
      </main>
    </div>
  );
};

