import React from 'react';
import { FileUpload } from './FileUpload';
import { fileToBase64 } from '../services/utils';

interface CharacterInputProps {
  label: string;
  mode: 'upload' | 'text';
  onModeChange: (mode: 'upload' | 'text') => void;
  imagePreview: string | null;
  onImageSelect: (base64: string) => void;
  description: string;
  onDescriptionChange: (text: string) => void;
  placeholder?: string;
}

export const CharacterInput: React.FC<CharacterInputProps> = ({
  label,
  mode,
  onModeChange,
  imagePreview,
  onImageSelect,
  description,
  onDescriptionChange,
  placeholder
}) => {
  const handleFile = async (file: File) => {
    try {
      const base64 = await fileToBase64(file);
      onImageSelect(base64);
    } catch (e) {
      alert("Error reading file");
    }
  };

  return (
    <div className="flex flex-col gap-3">
      <div className="flex items-center justify-between">
        <label className="text-sm font-medium text-gray-400">{label}</label>
        <div className="flex bg-[#181818] rounded-lg p-1 border border-gray-700">
          <button 
            onClick={() => onModeChange('upload')}
            className={`px-3 py-1 text-xs font-medium rounded-md transition-all ${mode === 'upload' ? 'bg-gray-700 text-white' : 'text-gray-400 hover:text-gray-200'}`}
          >Upload</button>
          <button 
            onClick={() => onModeChange('text')}
            className={`px-3 py-1 text-xs font-medium rounded-md transition-all ${mode === 'text' ? 'bg-gray-700 text-white' : 'text-gray-400 hover:text-gray-200'}`}
          >Describe</button>
        </div>
      </div>

      {mode === 'upload' ? (
        <div className="h-full">
          <FileUpload 
            label="" 
            accept="image/*" 
            onFileSelect={handleFile} 
            previewUrl={imagePreview || undefined}
            icon={<span className="text-3xl">👤</span>}
          />
        </div>
      ) : (
        <div className="w-full aspect-[9/16] max-h-64 sm:max-h-80">
          <textarea 
            className="w-full h-full bg-[#181818] border border-gray-700 rounded-xl p-4 text-sm focus:outline-none focus:ring-2 focus:ring-shorts-red resize-none placeholder-gray-600 text-gray-200 leading-relaxed"
            placeholder={placeholder || "Describe the character..."}
            value={description}
            onChange={(e) => onDescriptionChange(e.target.value)}
          />
        </div>
      )}
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { Scene } from "../types";
import { fileToBase64, extractFrameFromVideo } from "./utils";

// Initialize Gemini Client
const getAiClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

export const checkApiKey = async (): Promise<boolean> => {
  if (window.aistudio && window.aistudio.hasSelectedApiKey) {
     return await window.aistudio.hasSelectedApiKey();
  }
  return true; 
};

export const requestApiKey = async () => {
  if (window.aistudio && window.aistudio.openSelectKey) {
    await window.aistudio.openSelectKey();
  }
};

export const analyzeVideoStyle = async (videoFile: File): Promise<string> => {
  const ai = getAiClient();

  let base64Image: string | null = null;

  try {
     base64Image = await extractFrameFromVideo(videoFile);
  } catch (e) {
     console.warn("Frame extraction failed", e);
     if (videoFile.size < 10 * 1024 * 1024) {
        try {
          base64Image = await fileToBase64(videoFile);
        } catch (err) {
          console.warn("Fallback upload failed", err);
        }
     }
  }

  if (!base64Image) {
    return "Cinematic, high definition, viral youtube shorts aesthetic, dynamic lighting";
  }

  const modelId = "gemini-3-flash-preview"; 

  const prompt = `
    Analyze this image frame from a video. Describe the visual style, color palette, lighting, 
    and overall "vibe" (e.g., cyberpunk, fast-paced, minimalist, cinematic). 
    Keep it concise (under 50 words). This description will be used to generate similar images.
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: {
        parts: [
          { inlineData: { mimeType: "image/jpeg", data: base64Image } },
          { text: prompt },
        ],
      },
    });
    return response.text || "Cinematic, high quality, trending on social media";
  } catch (error) {
    console.error("Video analysis failed", error);
    return "Cinematic, high quality";
  }
};

export const generateScenesFromScript = async (
  script: string, 
  styleContext: string,
  pacing: 'fast' | 'slow' = 'fast'
): Promise<Scene[]> => {
  const ai = getAiClient();
  const modelId = "gemini-3-flash-preview";

  const pacingInstructions = pacing === 'fast' 
    ? "PACING: FAST / VIRAL. Break the script into many short, dynamic scenes. Use frequent cuts (every 2-4 seconds) to maintain high retention." 
    : "PACING: MINIMAL / ECONOMICAL. Consolidate the script into the FEWEST number of scenes possible. Group long segments of text into single scenes. Only cut if the visual context MUST change.";

  const prompt = `
    You are an expert Director of Photography and Storyboard Artist for viral YouTube Shorts.
    Your goal is to create a visual flow based on the requested pacing strategy.

    Break down the following script into visual scenes. 

    ${pacingInstructions}

    CRITICAL INSTRUCTIONS FOR VISUALS:
    1. AVOID generic flat shots. Use DYNAMIC ANGLES (Low angle, Dutch angle, Bird's eye, Extreme Close-up).
    2. Focus on ACTION and EMOTION. If the script is informational, visualize the concept metaphorically or with high drama.
    3. The visual style context is: ${styleContext}.

    IMPORTANT: 
    - Generate scenes to cover the ENTIRE script.
    ${pacing === 'fast' ? '- Do not limit the number of scenes.' : '- STRICTLY LIMIT the number of scenes to the absolute minimum.'}

    Return a list of scenes. For each scene provide:
    1. The segment of the script being spoken.
    2. A detailed visual prompt. MUST include specific camera instructions (e.g., "Wide shot from below," "Extreme close up on eyes").
       If the script mentions a character, refer to them as "the main character". If there are multiple characters, refer to them by their descriptions.
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: [
        { text: prompt },
        { text: `SCRIPT:\n${script}` }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              scriptSegment: { type: Type.STRING },
              visualPrompt: { type: Type.STRING, description: "Detailed, dynamic image generation prompt with camera angles" },
            },
            required: ["scriptSegment", "visualPrompt"],
          },
        },
      },
    });

    if (response.text) {
      const rawScenes = JSON.parse(response.text);
      return rawScenes.map((s: any, index: number) => ({
        id: `scene-${index}-${Date.now()}`,
        scriptSegment: s.scriptSegment,
        visualPrompt: s.visualPrompt,
        status: 'pending'
      }));
    }
    return [];
  } catch (error) {
    console.error("Scene generation failed", error);
    throw error;
  }
};

export interface CharConfig {
  image: string | null;
  description: string | null;
}

/**
 * Generates an image for a specific scene using up to two character references.
 */
export const generateSceneImage = async (
  scene: Scene, 
  mainChar: CharConfig,
  secondChar: CharConfig
): Promise<string> => {
  const ai = getAiClient();
  const modelId = "gemini-3-pro-image-preview"; 

  const parts: any[] = [];
  let promptText = "";

  // 1. Add Main Character Reference
  if (mainChar.image) {
    parts.push({
      inlineData: { mimeType: "image/png", data: mainChar.image },
    });
    promptText += "REFERENCE IMAGE 1: MAIN CHARACTER. Use this image as the primary reference for the main subject.\n";
  }
  if (mainChar.description) {
    promptText += `MAIN CHARACTER DESCRIPTION: ${mainChar.description}\n`;
  }

  // 2. Add Second Character Reference
  if (secondChar.image) {
    parts.push({
      inlineData: { mimeType: "image/png", data: secondChar.image },
    });
    promptText += "REFERENCE IMAGE 2: SECONDARY CHARACTER. Use this image as the reference for the second character if present in the scene.\n";
  }
  if (secondChar.description) {
    promptText += `SECONDARY CHARACTER DESCRIPTION: ${secondChar.description}\n`;
  }

  // 3. Main Scene Prompt
  promptText += `
    \nGENERATE SCENE:
    Action/Composition: ${scene.visualPrompt}

    CRITICAL INSTRUCTIONS:
    1. Aspect Ratio: 9:16 (Vertical) for YouTube Shorts.
    2. Style: High budget, cinematic, detailed.
    3. Consistency: Maintain the facial features and clothing of the referenced characters.
    4. Environment: Use the environment from Reference Image 1 if available, unless the scene prompt explicitly changes the location.
    5. If the scene prompt involves both characters, position them naturally.
  `;

  parts.push({ text: promptText });

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: { parts },
      config: {
        imageConfig: {
          aspectRatio: "9:16",
          imageSize: "2K" 
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    throw new Error("No image data found in response");
  } catch (error) {
    console.error("Image generation failed", error);
    throw error;
  }
};

import React, { useState } from 'react';
import { createRoot } from 'react-dom/client';
import { Scene, AppStep } from './types';
import { analyzeVideoStyle, generateScenesFromScript, generateSceneImage } from './services/geminiService';
import { cleanBase64 } from './services/utils';
import { FileUpload } from './components/FileUpload';
import { CharacterInput } from './components/CharacterInput';
import { SceneCard } from './components/SceneCard';
import { ApiKeyModal } from './components/ApiKeyModal';

const App: React.FC = () => {
  const [apiKeyReady, setApiKeyReady] = useState(false);
  const [step, setStep] = useState<AppStep>(AppStep.SETUP);
  const [loading, setLoading] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState('');
  const [generationProgress, setGenerationProgress] = useState<{ completed: number; total: number } | null>(null);

  // Character 1 Inputs
  const [char1Mode, setChar1Mode] = useState<'upload' | 'text'>('upload');
  const [char1Image, setChar1Image] = useState<string | null>(null);
  const [char1Desc, setChar1Desc] = useState('');

  // Character 2 Inputs
  const [char2Mode, setChar2Mode] = useState<'upload' | 'text'>('upload');
  const [char2Image, setChar2Image] = useState<string | null>(null);
  const [char2Desc, setChar2Desc] = useState('');

  const [referenceVideo, setReferenceVideo] = useState<File | null>(null);
  const [referenceVideoUrl, setReferenceVideoUrl] = useState<string | null>(null);
  const [script, setScript] = useState('');
  const [pacing, setPacing] = useState<'fast' | 'slow'>('fast');

  const [stylePrompt, setStylePrompt] = useState("Cinematic, high definition, viral youtube shorts aesthetic, dynamic lighting");
  const [isAnalyzingStyle, setIsAnalyzingStyle] = useState(false);

  const [styleDescription, setStyleDescription] = useState<string>('');
  const [scenes, setScenes] = useState<Scene[]>([]);

  const handleVideoUpload = async (file: File) => {
    setReferenceVideo(file);
    setReferenceVideoUrl(URL.createObjectURL(file));

    setIsAnalyzingStyle(true);
    try {
        const analyzedStyle = await analyzeVideoStyle(file);
        setStylePrompt(analyzedStyle);
    } catch (e) {
        console.error("Style analysis failed", e);
    } finally {
        setIsAnalyzingStyle(false);
    }
  };

  const startStoryboard = async () => {
    if (!script.trim()) return alert("Please enter a script");

    setLoading(true);
    setStep(AppStep.STORYBOARD);

    try {
      const currentStyle = stylePrompt;
      setStyleDescription(currentStyle);

      setLoadingMessage('Director AI is planning your shots...');
      const generatedScenes = await generateScenesFromScript(script, currentStyle, pacing);
      setScenes(generatedScenes);

      setLoading(false);
    } catch (error) {
      console.error(error);
      alert("Failed to generate storyboard. See console for details.");
      setStep(AppStep.SETUP);
      setLoading(false);
    }
  };

  const getCleanCharConfig = (mode: 'upload' | 'text', image: string | null, desc: string) => {
    return {
      image: (mode === 'upload' && image) ? cleanBase64(image) : null,
      description: (mode === 'text') ? desc : null
    };
  };

  const generateAllImages = async () => {
    const scenesToGenerate = scenes.filter(s => s.status !== 'completed');
    if (scenesToGenerate.length === 0) {
        alert("All scenes are already generated!");
        return;
    }

    setGenerationProgress({ completed: 0, total: scenesToGenerate.length });
    setScenes(prev => prev.map(s => s.status === 'completed' ? s : { ...s, status: 'generating' }));

    const mainChar = getCleanCharConfig(char1Mode, char1Image, char1Desc);
    const secondChar = getCleanCharConfig(char2Mode, char2Image, char2Desc);

    let completedCount = 0;

    for (const scene of scenes) {
        if (scene.status === 'completed') continue;

        try {
            const base64Image = await generateSceneImage(scene, mainChar, secondChar);

            setScenes(current => current.map(s => {
                if (s.id === scene.id) {
                    return { ...s, status: 'completed', imageUrl: base64Image };
                }
                return s;
            }));
        } catch (e) {
            console.error(`Failed scene ${scene.id}`, e);
            setScenes(current => current.map(s => {
                if (s.id === scene.id) {
                    return { ...s, status: 'error' };
                }
                return s;
            }));
        } finally {
            completedCount++;
            setGenerationProgress({ completed: completedCount, total: scenesToGenerate.length });
        }
    }

    setTimeout(() => setGenerationProgress(null), 1000);
  };

  const generateSingleScene = async (targetScene: Scene) => {
     setScenes(current => current.map(s => s.id === targetScene.id ? { ...s, status: 'generating' } : s));

     const mainChar = getCleanCharConfig(char1Mode, char1Image, char1Desc);
     const secondChar = getCleanCharConfig(char2Mode, char2Image, char2Desc);

     try {
        const base64Image = await generateSceneImage(targetScene, mainChar, secondChar);
        setScenes(current => current.map(s => {
            if (s.id === targetScene.id) {
                return { ...s, status: 'completed', imageUrl: base64Image };
            }
            return s;
        }));
     } catch (e) {
        setScenes(current => current.map(s => s.id === targetScene.id ? { ...s, status: 'error' } : s));
     }
  };

  const downloadAllImages = async () => {
    const completedScenes = scenes.filter(s => s.imageUrl);

    if (completedScenes.length === 0) {
      alert("No generated images to download yet! Click 'Generate All Images' first.");
      return;
    }

    if (completedScenes.length < scenes.length) {
       const confirm = window.confirm(`Only ${completedScenes.length} of ${scenes.length} scenes are ready. Download them anyway?`);
       if (!confirm) return;
    }

    for (let i = 0; i < completedScenes.length; i++) {
      const scene = completedScenes[i];
      if (scene.imageUrl) {
        const link = document.createElement('a');
        link.href = scene.imageUrl;
        const paddedIndex = (i + 1).toString().padStart(2, '0');
        link.download = `scene_${paddedIndex}.png`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        await new Promise(resolve => setTimeout(resolve, 500));
      }
    }
  };

  if (!apiKeyReady) {
      return <ApiKeyModal onReady={() => setApiKeyReady(true)} />;
  }

  return (
    <div className="min-h-screen bg-[#0F0F0F] text-white font-sans selection:bg-shorts-red selection:text-white">
      <header className="fixed top-0 left-0 right-0 z-40 bg-[#0F0F0F]/90 backdrop-blur-md border-b border-gray-800 h-16 flex items-center px-6 justify-between">
        <div className="flex items-center gap-2">
           <div className="w-8 h-8 bg-shorts-red rounded-lg flex items-center justify-center font-bold text-white">S</div>
           <h1 className="text-xl font-bold tracking-tight">Shorts AI <span className="text-gray-500 font-normal">Storyboarder</span></h1>
        </div>

        <div className="flex gap-4">
          {step === AppStep.STORYBOARD && (
            <>
              <button 
                onClick={downloadAllImages}
                className="text-sm font-semibold text-shorts-accent hover:text-blue-400 transition-colors flex items-center gap-1"
                disabled={!!generationProgress}
              >
                <span>⬇️</span> Download Images
              </button>
              <button 
                onClick={() => setStep(AppStep.SETUP)}
                className="text-sm text-gray-400 hover:text-white transition-colors"
                disabled={!!generationProgress}
              >
                Start Over
              </button>
            </>
          )}
        </div>
      </header>

      <main className="pt-24 pb-20 px-4 max-w-7xl mx-auto">

        {step === AppStep.SETUP && (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 animate-fade-in">
            {/* Left Col: Inputs */}
            <div className="space-y-8">
              <div className="space-y-2">
                <h2 className="text-3xl font-bold">Create your next viral Short.</h2>
                <p className="text-gray-400">Import up to two characters, define a style, and let AI visualize your script.</p>
              </div>

              <div className="grid grid-cols-2 gap-6">

                {/* Main Character */}
                <CharacterInput
                  label="Main Character"
                  mode={char1Mode}
                  onModeChange={setChar1Mode}
                  imagePreview={char1Image}
                  onImageSelect={setChar1Image}
                  description={char1Desc}
                  onDescriptionChange={setChar1Desc}
                  placeholder="Describe your main character... e.g., 'A futuristic samurai with a glowing blue katana'"
                />

                {/* Second Character */}
                <CharacterInput
                  label="Second Character (Optional)"
                  mode={char2Mode}
                  onModeChange={setChar2Mode}
                  imagePreview={char2Image}
                  onImageSelect={setChar2Image}
                  description={char2Desc}
                  onDescriptionChange={setChar2Desc}
                  placeholder="Describe a sidekick, villain, or secondary character..."
                />

                {/* Style Video - Spanning full width if needed, or just next row */}
                <div className="col-span-2">
                   <div className="h-px bg-gray-800 my-2"></div>
                </div>

                <div className="col-span-2 sm:col-span-1">
                   <FileUpload 
                      label="Style Reference Video (Optional)" 
                      accept="video/*" 
                      onFileSelect={handleVideoUpload} 
                      previewUrl={referenceVideoUrl || undefined}
                      isVideo={true}
                      icon={<span className="text-3xl">🎥</span>}
                    />
                </div>
              </div>

              {/* Style Editor */}
              <div className="space-y-3">
                 <div className="flex items-center justify-between">
                    <label className="text-sm font-medium text-gray-400">Visual Style & Art Direction</label>
                    {isAnalyzingStyle && (
                        <span className="text-xs font-semibold text-shorts-accent animate-pulse flex items-center gap-1">
                            <span className="w-2 h-2 rounded-full bg-shorts-accent"></span>
                            Extracting style from video...
                        </span>
                    )}
                 </div>
                 <textarea
                    className="w-full bg-[#181818] border border-gray-700 rounded-xl p-4 text-sm leading-relaxed text-gray-200 focus:outline-none focus:ring-2 focus:ring-shorts-red resize-none transition-all placeholder-gray-600"
                    rows={3}
                    placeholder="Describe the look and feel (e.g., 'Cyberpunk city, neon lights, high contrast, 3D render')"
                    value={stylePrompt}
                    onChange={(e) => setStylePrompt(e.target.value)}
                 />
              </div>
            </div>

            {/* Right Col: Script & Action */}
            <div className="flex flex-col h-full space-y-6">
               <label className="block text-sm font-medium text-gray-400">Video Script</label>
               <textarea
                 className="flex-1 w-full bg-[#1E1E1E] border border-gray-700 rounded-xl p-6 text-lg leading-relaxed focus:outline-none focus:ring-2 focus:ring-shorts-red resize-none transition-all placeholder-gray-600"
                 placeholder="Paste your YouTube Short script here... (e.g., 'Did you know that octopuses have three hearts? It's true! Two pump blood to the gills...')"
                 value={script}
                 onChange={(e) => setScript(e.target.value)}
               />

               <div className="bg-[#181818] p-4 rounded-xl border border-gray-700 space-y-3">
                  <label className="text-sm font-medium text-gray-400 block">Pacing & Scene Count</label>
                  <div className="flex gap-4">
                    <button
